    related_articles: ["čl. 367. st. 2. ZOO CG","čl. 347. st. 4. ZOO CG","čl. 9. ZOO CG","čl. 379. ZOO CG","čl. 3. ZOO CG","čl. 367. st. 1. ZOO CG","čl. 9. st. 3. ZOO CG","čl. 4. ZOO CG","čl. 383. st. 1. ZOO CG"],
